package com.recettealarm.app;

import android.app.*;import android.content.*;import android.graphics.*;import android.graphics.drawable.*;import android.net.*;import android.text.InputType;import android.view.*;import android.widget.*;

public class UI{
 static int lime=Color.rgb(202,245,72),lime2=Color.rgb(228,252,153),green=Color.rgb(5,67,55),green2=Color.rgb(14,99,82),dark=Color.rgb(15,18,17),muted=Color.rgb(110,116,112),bg=Color.rgb(248,248,244),card=Color.WHITE,soft=Color.rgb(242,244,239),danger=Color.rgb(210,50,43),gold=Color.rgb(255,196,39),cream=Color.rgb(255,253,245);
 static int dp(Context c,int v){return (int)(v*c.getResources().getDisplayMetrics().density+0.5f);}static GradientDrawable bg(int color,int radius){GradientDrawable g=new GradientDrawable();g.setColor(color);g.setCornerRadius(radius);return g;}static GradientDrawable stroke(Context c,int color,int radius,int sc){GradientDrawable g=bg(color,radius);g.setStroke(dp(c,1),sc);return g;}static GradientDrawable grad(int c1,int c2,int radius){GradientDrawable g=new GradientDrawable(GradientDrawable.Orientation.TL_BR,new int[]{c1,c2});g.setCornerRadius(radius);return g;}
 static TextView tv(Context c,String t,int sp,int style){TextView v=new TextView(c);v.setText(t==null?"":t);v.setTextSize(sp);v.setTypeface(Typeface.DEFAULT,style);v.setTextColor(dark);v.setPadding(dp(c,4),dp(c,3),dp(c,4),dp(c,3));v.setLineSpacing(dp(c,2),1.05f);return v;}static TextView muted(Context c,String t,int sp){TextView v=tv(c,t,sp,Typeface.NORMAL);v.setTextColor(muted);return v;}static TextView center(Context c,String t,int sp,int style){TextView v=tv(c,t,sp,style);v.setGravity(Gravity.CENTER);return v;}
 static Button btn(Context c,String t){Button b=new Button(c);b.setText(t);b.setAllCaps(false);b.setTextColor(Color.WHITE);b.setTextSize(15);b.setTypeface(Typeface.DEFAULT,Typeface.BOLD);b.setPadding(dp(c,12),dp(c,8),dp(c,12),dp(c,8));b.setBackground(grad(green,green2,dp(c,26)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(c,54));lp.setMargins(0,dp(c,7),0,dp(c,7));b.setLayoutParams(lp);return b;}static Button limeBtn(Context c,String t){Button b=btn(c,t);b.setTextColor(dark);b.setBackground(grad(lime,lime2,dp(c,28)));return b;}static Button whiteBtn(Context c,String t){Button b=btn(c,t);b.setTextColor(dark);b.setBackground(stroke(c,Color.WHITE,dp(c,26),Color.rgb(224,228,221)));return b;}static Button dangerBtn(Context c,String t){Button b=btn(c,t);b.setBackground(grad(danger,Color.rgb(230,92,70),dp(c,28)));return b;}static Button oliveBtn(Context c,String t){return limeBtn(c,t);}
 static EditText input(Context c,String h){EditText e=new EditText(c);e.setHint(h);e.setTextSize(15);e.setTextColor(dark);e.setHintTextColor(Color.rgb(151,157,153));e.setSingleLine(false);e.setMinLines(1);e.setPadding(dp(c,16),dp(c,12),dp(c,16),dp(c,12));e.setBackground(stroke(c,Color.WHITE,dp(c,22),Color.rgb(226,228,223)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(c,5),0,dp(c,8));e.setLayoutParams(lp);return e;}static EditText area(Context c,String h){EditText e=input(c,h);e.setMinLines(3);e.setGravity(Gravity.TOP);return e;}static EditText number(Context c,String h){EditText e=input(c,h);e.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_FLAG_DECIMAL);return e;}
 static LinearLayout root(Activity a){ScrollView sv=new ScrollView(a);sv.setFillViewport(true);LinearLayout l=new LinearLayout(a);l.setOrientation(LinearLayout.VERTICAL);l.setPadding(dp(a,15),dp(a,16),dp(a,15),dp(a,26));l.setBackgroundColor(bg);sv.addView(l,new ScrollView.LayoutParams(-1,-2));a.setContentView(sv);return l;}static LinearLayout row(Context c){LinearLayout l=new LinearLayout(c);l.setOrientation(LinearLayout.HORIZONTAL);l.setGravity(Gravity.CENTER_VERTICAL);return l;}static LinearLayout section(Context c){LinearLayout box=new LinearLayout(c);box.setOrientation(LinearLayout.VERTICAL);box.setPadding(dp(c,16),dp(c,14),dp(c,16),dp(c,14));box.setBackground(stroke(c,card,dp(c,28),Color.rgb(230,233,226)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(c,8),0,dp(c,12));box.setLayoutParams(lp);return box;}
 static LinearLayout glassHero(Context c,String title,String sub){LinearLayout h=new LinearLayout(c);h.setOrientation(LinearLayout.VERTICAL);h.setPadding(dp(c,22),dp(c,20),dp(c,18),dp(c,20));h.setBackground(grad(Color.rgb(228,252,166),Color.rgb(249,255,235),dp(c,34)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(c,7),0,dp(c,14));h.setLayoutParams(lp);TextView a=tv(c,title,30,Typeface.BOLD);h.addView(a);TextView s=muted(c,sub,15);s.setPadding(dp(c,5),dp(c,6),dp(c,5),0);h.addView(s);return h;}static LinearLayout hero(Context c,String icon,String title,String sub){return glassHero(c,icon+"  "+title,sub);}
 static TextView chip(Context c,String t,boolean active){TextView v=center(c,t,13,Typeface.BOLD);v.setTextColor(dark);v.setBackground(active?grad(lime,lime2,dp(c,36)):stroke(c,Color.WHITE,dp(c,36),Color.rgb(226,228,223)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-2,dp(c,46));lp.setMargins(0,dp(c,5),dp(c,9),dp(c,7));v.setMinWidth(dp(c,82));v.setGravity(Gravity.CENTER);v.setLayoutParams(lp);return v;}static TextView card(Context c,String t){TextView v=tv(c,t,16,Typeface.BOLD);v.setBackground(stroke(c,Color.WHITE,dp(c,26),Color.rgb(229,232,226)));v.setPadding(dp(c,17),dp(c,15),dp(c,17),dp(c,15));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(c,6),0,dp(c,8));v.setLayoutParams(lp);return v;}static TextView smallCard(Context c,String t){TextView v=card(c,t);v.setTextSize(15);v.setTypeface(Typeface.DEFAULT,Typeface.NORMAL);return v;}
 static TextView iconBtn(Context c,String t){TextView v=center(c,t,25,Typeface.BOLD);v.setTextColor(dark);v.setBackground(stroke(c,Color.WHITE,dp(c,18),Color.rgb(226,228,223)));v.setGravity(Gravity.CENTER);LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(dp(c,54),dp(c,54));lp.setMargins(0,0,dp(c,8),dp(c,8));v.setLayoutParams(lp);return v;}static TextView pill(Context c,String t,int color){TextView v=center(c,t,12,Typeface.BOLD);v.setTextColor(color==lime?dark:Color.WHITE);v.setBackground(bg(color,dp(c,24)));v.setPadding(dp(c,10),dp(c,5),dp(c,10),dp(c,5));return v;}
 static ImageView image(Context c,String uri,int h){ImageView iv=new ImageView(c);iv.setScaleType(ImageView.ScaleType.CENTER_CROP);iv.setBackground(grad(Color.rgb(234,242,225),Color.rgb(250,253,239),dp(c,28)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(c,h));lp.setMargins(0,dp(c,6),0,dp(c,8));iv.setLayoutParams(lp);try{if(uri!=null&&uri.trim().length()>0)iv.setImageURI(Uri.parse(uri));else iv.setImageDrawable(null);}catch(Exception e){iv.setImageDrawable(null);}return iv;}
 static FrameLayout foodHero(Context c,String uri,int h,String emoji,String title){FrameLayout f=new FrameLayout(c);f.setBackground(grad(Color.rgb(225,242,213),Color.rgb(249,255,235),dp(c,30)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(c,h));lp.setMargins(0,dp(c,6),0,dp(c,8));f.setLayoutParams(lp);ImageView img=image(c,uri,h);img.setLayoutParams(new FrameLayout.LayoutParams(-1,-1));f.addView(img);if(uri==null||uri.trim().isEmpty()){LinearLayout overlay=new LinearLayout(c);overlay.setOrientation(LinearLayout.VERTICAL);overlay.setGravity(Gravity.CENTER);TextView e=center(c,emoji==null?"🍽":emoji,48,Typeface.BOLD);TextView tx=center(c,title==null?"Recette":title,15,Typeface.BOLD);tx.setTextColor(green);overlay.addView(e);overlay.addView(tx);f.addView(overlay,new FrameLayout.LayoutParams(-1,-1));}return f;}
 static TextView navItem(Context c,String t){TextView v=center(c,t,12,Typeface.BOLD);v.setTextColor(dark);v.setPadding(dp(c,8),dp(c,7),dp(c,8),dp(c,7));return v;}static LinearLayout bottomNav(Context c){LinearLayout n=row(c);n.setGravity(Gravity.CENTER);n.setPadding(dp(c,8),dp(c,6),dp(c,8),dp(c,6));n.setBackground(stroke(c,Color.WHITE,dp(c,28),Color.rgb(226,229,222)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(c,10),0,dp(c,10));n.setLayoutParams(lp);return n;}
 static TextView metric(Context c,String icon,String value,String label){TextView v=center(c,icon+"\n"+value+"\n"+label,12,Typeface.BOLD);v.setBackground(stroke(c,Color.WHITE,dp(c,24),Color.rgb(228,232,225)));v.setPadding(0,dp(c,9),0,dp(c,9));return v;}
 static String stars(int r){if(r<0)r=0;if(r>5)r=5;String s="";for(int i=1;i<=5;i++)s+=i<=r?"★":"☆";return s;}static void toast(Context c,String s){Toast.makeText(c,s,Toast.LENGTH_SHORT).show();}
}
